/*
 * fmodf() test harness — prints (input_hex, divisor_hex, output_hex) triples.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly fmodf  (test_fmodf_opt.elf)
 *   2. Linked with toolchain's default fmodf        (test_fmodf_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint32_t f2u(float f)
{
    union { float f; uint32_t u; } x;
    x.f = f;
    return x.u;
}

static inline float u2f(uint32_t u)
{
    union { float f; uint32_t u; } x;
    x.u = u;
    return x.f;
}

static volatile float g_acc;

static void emit(float x, float y)
{
#ifdef EN_PERF
    volatile float vx = x;  /* prevent constant-folding of literal arguments */
    volatile float vy = y;
    g_acc += fmodf(vx, vy);
#else
    float r = fmodf(x, y);
    printf("%08lx %08lx %08lx\n",
           (unsigned long)f2u(x), (unsigned long)f2u(y), (unsigned long)f2u(r));
#endif
}

static void emit_u(uint32_t x_bits, uint32_t y_bits)
{
    emit(u2f(x_bits), u2f(y_bits));
}

/* ------------------------------------------------------------------ */
/* 100 representative test points                                      */
/* ------------------------------------------------------------------ */

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (11) --- */
    emit(0.0f,  1.0f);                          /* +0 numerator */
    emit(-0.0f, 1.0f);                          /* -0 numerator */
    emit(1.0f,  0.0f);                          /* y=0 -> NaN (undefined) */
    emit_u(0x7fc00000u, 0x3f800000u);           /* qNaN numerator */
    emit_u(0xffc00000u, 0x3f800000u);           /* -qNaN numerator */
    emit_u(0x7f800001u, 0x3f800000u);           /* sNaN numerator */
    emit_u(0x3f800000u, 0x7fc00000u);           /* qNaN denominator */
    emit_u(0x7f800000u, 0x3f800000u);           /* +Inf numerator -> NaN */
    emit_u(0xff800000u, 0x3f800000u);           /* -Inf numerator -> NaN */
    emit(1.0f, u2f(0x7f800000u));               /* 1 mod +Inf = 1 */
    emit(1.0f, u2f(0xff800000u));               /* 1 mod -Inf = 1 */

    /* --- Section 2: Subnormal (denormal) values (6) --- */
    emit_u(0x00000001u, 0x3f800000u);           /* min positive subnormal: 2^-149 */
    emit_u(0x80000001u, 0x3f800000u);           /* min negative subnormal */
    emit_u(0x00400000u, 0x3f800000u);           /* mid subnormal */
    emit_u(0x80400000u, 0x3f800000u);           /* mid negative subnormal */
    emit_u(0x007fffffu, 0x3f800000u);           /* max subnormal: just below FLT_MIN */
    emit_u(0x807fffffu, 0x3f800000u);           /* max negative subnormal */

    /* --- Section 3: Normal boundary values (6) --- */
    emit(FLT_MIN,  1.0f);                       /* smallest normal: 2^-126 */
    emit(-FLT_MIN, 1.0f);                       /* negative smallest normal */
    emit_u(0x00800001u, 0x3f800000u);           /* one ULP above FLT_MIN */
    emit(FLT_MAX,  1.0e30f);                    /* largest normal numerator */
    emit(-FLT_MAX, 1.0e30f);                    /* largest negative numerator */
    emit_u(0x7f7ffffeu, 0x5f000000u);           /* one ULP below FLT_MAX */

    /* --- Section 4: Near 1.0 ULP density (8) --- */
    emit_u(0x3f7fffffu, 0x3f000000u);           /* one ULP below 1.0, y=0.5 */
    emit(1.0f,  0.5f);                          /* 1.0 mod 0.5 = 0.0 */
    emit_u(0x3f800001u, 0x3f000000u);           /* one ULP above 1.0, y=0.5 */
    emit_u(0x3f7ffff0u, 0x3e800000u);           /* a few ULPs below 1.0, y=0.25 */
    emit_u(0x3f800010u, 0x3e800000u);           /* a few ULPs above 1.0, y=0.25 */
    emit(-1.0f, 0.5f);                          /* -1.0 mod 0.5 = -0.0 */
    emit_u(0xbf7fffffu, 0x3f000000u);           /* one ULP toward zero from -1.0 */
    emit_u(0xbf800001u, 0x3f000000u);           /* one ULP away from zero from -1.0 */

    /* --- Section 5: Exponent switching points (6) --- */
    emit_u(0x3f000001u, 0x3e800000u);           /* one ULP above 0.5, y=0.25 */
    emit(0.5f,  0.3f);                          /* 0.5 mod 0.3 = 0.2 */
    emit_u(0x3effffffu, 0x3e800000u);           /* one ULP below 0.5, y=0.25 */
    emit_u(0x40000001u, 0x3f800000u);           /* one ULP above 2.0, y=1.0 */
    emit(2.0f,  1.5f);                          /* 2.0 mod 1.5 = 0.5 */
    emit_u(0x3fffffffu, 0x3f800000u);           /* one ULP below 2.0, y=1.0 */

    /* --- Section 6: x<y, x=y, x>y cases (14) --- */
    emit(0.5f,  1.0f);                          /* x < y: result = x */
    emit(0.1f,  1.0f);                          /* x < y: small x */
    emit(0.9999f, 1.0f);                        /* x just below y */
    emit(1.0f,  1.0f);                          /* x = y: result = 0 */
    emit(2.0f,  2.0f);                          /* x = y: result = 0 */
    emit(3.14159265f, 3.14159265f);             /* x = y: irrational */
    emit(2.0f,  1.0f);                          /* x = 2y: result = 0 */
    emit(3.0f,  2.0f);                          /* x = 1.5y: result = 1 */
    emit(5.0f,  3.0f);                          /* x > y: result = 2 */
    emit(7.0f,  3.0f);                          /* x = 2y+1: result = 1 */
    emit(10.0f, 3.0f);                          /* x = 3y+1: result = 1 */
    emit(100.0f, 7.0f);                         /* larger quotient */
    emit(-0.5f, 1.0f);                          /* negative x < |y|: result = -x */
    emit(-3.0f, 2.0f);                          /* negative x > |y| */

    /* --- Section 7: Large numerator (8) --- */
    emit(1.0e10f,  1.0f);                       /* very large x, y=1 */
    emit(-1.0e10f, 1.0f);                       /* very large negative x */
    emit(1.0e10f,  3.0f);                       /* large x, y=3 */
    emit(1.0e10f,  7.0f);                       /* large x, y=7 */
    emit_u(0x4b400000u, 0x40490fdbu);           /* 12582912.0 mod pi */
    emit_u(0x4dc90fdbu, 0x40490fdbu);           /* 100*pi mod pi = 0 */
    emit(1.0e7f,  100.0f);                      /* moderate large */
    emit(-1.0e7f, 100.0f);                      /* moderate large negative */

    /* --- Section 8: Sign combinations (8) --- */
    emit(5.0f,   3.0f);                         /* (+, +) */
    emit(-5.0f,  3.0f);                         /* (-, +): result negative */
    emit(5.0f,  -3.0f);                         /* (+, -): result positive */
    emit(-5.0f, -3.0f);                         /* (-, -): result negative */
    emit(10.5f,  3.5f);                         /* (+, +) non-integer */
    emit(-10.5f, 3.5f);                         /* (-, +) non-integer */
    emit(10.5f, -3.5f);                         /* (+, -) non-integer */
    emit(-10.5f, -3.5f);                        /* (-, -) non-integer */

    /* --- Section 9: Small remainder / edge cases (8) --- */
    emit(10.001f,   1.0f);                      /* tiny remainder above integer */
    emit(10.0001f,  1.0f);                      /* very tiny remainder */
    emit(10.99f,    1.0f);                      /* nearly 1 ULP below next integer */
    emit(10.999f,   1.0f);                      /* even closer to next integer */
    emit(-10.001f,  1.0f);                      /* negative tiny remainder */
    emit(-10.999f,  1.0f);                      /* negative near-integer */
    emit_u(0x3f800000u, 0x3f800000u);           /* 1.0 mod 1.0 = 0 (exact) */
    emit_u(0x40000000u, 0x3f800000u);           /* 2.0 mod 1.0 = 0 (exact) */

    /* --- Section 10: Mixed magnitude pairs (33) --- */
    /* Pythagorean-inspired: fmod(5, 3)=2, (13, 5)=3 */
    emit(3.0f,   4.0f);                         /* 3 mod 4 = 3 (x < y) */
    emit(5.0f,   4.0f);                         /* 5 mod 4 = 1 */
    emit(13.0f,  5.0f);                         /* 13 mod 5 = 3 */
    /* Powers of 2 as divisors */
    emit(7.0f,   2.0f);                         /* 7 mod 2 = 1 */
    emit(15.0f,  4.0f);                         /* 15 mod 4 = 3 */
    emit(31.0f,  8.0f);                         /* 31 mod 8 = 7 */
    emit(63.0f,  16.0f);                        /* 63 mod 16 = 15 */
    /* Fractional divisors */
    emit(1.0f,   0.3f);                         /* 1.0 mod 0.3 */
    emit(1.0f,   0.7f);                         /* 1.0 mod 0.7 */
    emit(3.14159265f, 1.0f);                    /* pi mod 1 */
    emit(3.14159265f, 0.5f);                    /* pi mod 0.5 */
    emit(2.71828182f, 1.0f);                    /* e mod 1 */
    emit(2.71828182f, 0.5f);                    /* e mod 0.5 */
    /* Very small divisors */
    emit(1.0f,   FLT_MIN);                      /* many subtractions */
    emit(-1.0f,  FLT_MIN);                      /* negative, many subtractions */
    emit_u(0x00800000u, 0x00000001u);           /* FLT_MIN mod min-subnormal */
    /* Very small numerator, normal divisor */
    emit_u(0x00800000u, 0x3f800000u);           /* FLT_MIN mod 1.0 = FLT_MIN */
    emit_u(0x80800000u, 0x3f800000u);           /* -FLT_MIN mod 1.0 */
    /* Mixed exponent spreads */
    emit(1.0e6f,  1.0e3f);                      /* 1e6 mod 1e3 = 0 */
    emit(1.0e6f,  1.0e3f + 1.0f);              /* near-zero remainder */
    emit(1.0e-6f, 1.0e-9f);                     /* both small */
    emit(1.0e-6f, 3.0e-7f);                     /* x mod y where y < x */
    /* ULP neighbors of exact result = 0 */
    emit_u(0x40000000u, 0x40000000u);           /* 2.0 mod 2.0 = 0 */
    emit_u(0x40400000u, 0x40000000u);           /* 3.0 mod 2.0 = 1 */
    emit_u(0x40800000u, 0x40000000u);           /* 4.0 mod 2.0 = 0 */
    emit_u(0x40a00000u, 0x40000000u);           /* 5.0 mod 2.0 = 1 */
    /* Reciprocal pairs */
    emit(0.1f,  0.01f);                         /* 0.1 mod 0.01 */
    emit(1.0f,  0.1f);                          /* 1.0 mod 0.1 */
    emit(10.0f, 0.1f);                          /* 10.0 mod 0.1 */
    emit(1.23456789f, 0.123456789f);            /* arbitrary pair */
    emit(9.99999f, 3.33333f);                   /* near-exact multiple */
    emit_u(0x7f7fffffu, 0x7f7ffffeu);           /* FLT_MAX mod (FLT_MAX - 1 ULP) */
}

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf acc: %08lx\n", (unsigned long)f2u((float)g_acc));
#else
    test_representative_100();
#endif
    return 0;
}

